<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="popup-title">可升级列表</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'400rpx'}">
					<view class="list-box">
						<u-cell-group :border="false">
							<u-cell-item :title="item.label" v-for="(item,index) in list" :key="index"
								@click="itemClick(item,index)" :class="{on:curr ==index}">
								<view>¥ {{item.amount}}</view>
							</u-cell-item>
						</u-cell-group>
					</view>
				</scroll-view>
			</view>
			<!-- <view class="popup-footer">
				<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
			</view> -->
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			},
			show: {
				type: Boolean,
				default: false,
			},
			levelId: {
				type: [Number, String],
				default: 0
			},
		},
		data() {
			return {
				popupShow: false,
				list: [],
				curr: -1,
			};
		},
		computed: {

		},
		watch: {
			show(nv) {
				this.popupShow = nv
			},
			levelId: {
				handler(nv) {
					if (nv) {
						this.curr = this.list.findIndex(item => item.value == nv)
					}
				},
				immediate: true
			}
		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				await this.loadData()

				if (this.levelId) {
					this.curr = this.list.findIndex(item => item.value == this.levelId)
				}
				if (this.curr == -1) {
					if (Array.isArray(this.list) && this.list.length) {
						this.curr = 0
						this.$emit('change', this.list[0])
					}
				} else {
					this.$emit('change', this.list[this.curr])
				}
			},
			open() {},
			close() {
				this.$emit('update:show', false)
			},
			async loadData() {
				const {
					rangeLevel,
					up_level_tip
				} = await this.$u.api.upgradeConfig()
				this.list = rangeLevel
				if (up_level_tip) {
					this.$emit('showTip', up_level_tip)
				}
			},
			handelOk() {
				this.$emit('ok', {
					editForm: this.editForm,
					specValue: this.selectedSpecValue
				})
				this.close()
			},
			itemClick(row, index) {
				this.$emit('change', row)
				this.popupShow = false
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;
		min-height: 600rpx;

		.wrap {
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}

	.list-box {

		.on {
			background-color: #f29100 !important;
			color: #fff;
			border-radius: 10rpx;

			::v-deep {
				.u-cell__value {
					color: #fff;
				}
			}
		}
	}
</style>