<template>
	<u-cell-group :border="false">
		<u-cell-item :arrow="false" v-for="(item,index) in payList" :key="index"
			@click="handelChangePayWay(item,index)">
			<template #title>
				<view class="title-box">
					<u-image :src="$util.img(item.img)" width="60rpx" height="60rpx" border-radius="50%" />
					<view class="right">
						<view class="pay-title">
							{{item.title}}
						</view>
						<view class="pay-tips" v-if="item.tips">
							{{ item.tips }}
						</view>
					</view>

				</view>
			</template>
			<view class="content-box">
				<view>
					<text class="balance" v-if="item.name=='balance'">余额：{{balance}}元</text>
					<text class="fee" v-else>手续费：{{item.fee || '无'}}</text>
				</view>
				<view>
					<text style="color: #fa3534;" class="iconfont"
						:class="{'icon-danxuanxuanzhong':selectedPayIndex == index,'icon-danxuan':selectedPayIndex != index}"></text>
				</view>
			</view>
		</u-cell-item>
	</u-cell-group>
</template>

<script>
	export default {
		name: 'pay-way',
		components: {},
		props: {
			type: {
				type: String,
				required: true,
				default: ''
			},
			levelId: {
				type: Number,
				default: 0,
			},
		},
		data() {
			return {
				selectedPayIndex: -1,
				payList: []
			}
		},
		computed: {
			balance() {
				let find = this.payList.find((item) => item.name == 'balance')
				return find ? Number(find.money) : 0
			},
			queryForm() {
				return {
					type: this.type,
					level_id: this.levelId
				}
			}
		},
		watch: {
			queryForm: {
				handler() {
					this.fetchData()
				},
				deep: true
			}
		},
		created() {},
		mounted() {},
		methods: {
			handelChangePayWay(row, idx) {
				this.selectedPayIndex = idx
				this.$emit('change', row)
			},
			async fetchData() {
				const {
					pay_list
				} = await this.$u.api.payList(this.queryForm)
				this.payList = pay_list
				if (pay_list.length) {
					this.selectedPayIndex = 0
					this.$emit('change', pay_list[0])
				}
			}
		}
	}
</script>
<style scoped lang="scss" scoped>
	.title-box {
		display: flex;
		align-items: center;
		gap: 20rpx;

		.right {
			display: flex;
			flex-direction: column;
			gap: 10rpx;
			line-height: 38rpx;
			align-items: flex-start;

			.pay-title {
				position: relative;
			}

			.pay-tips {
				background-color: #e93323;
				color: #fff;
				font-size: 24rpx;
				padding: 2rpx 10rpx;
				border-radius: 6rpx;
			}
		}

	}

	.content-box {
		display: flex;
		justify-content: flex-end;
		gap: 30rpx;

		.fee {
			color: #fa3534;
		}
	}
</style>