<template>
	<view class="page">
		<view class="info-box">
			<u-cell-group :border="false">
				<u-cell-item title="当前等级" :arrow="false" hover-class="none">{{userinfo.level_name}}</u-cell-item>
				<u-cell-item title="等级列表" arrow :border-bottom="false"
					@click="visibleLevel = true">{{currLevel.label}}</u-cell-item>
			</u-cell-group>
		</view>
		<view class="info-box">
			<pay-way ref="pay-way" type="upgradation" :level-id="currLevel.value" @change="handelPayWayChange" />
		</view>
		<view class="pay-btn" @click="doSubmit">确认支付</view>
		<choose-level :show.sync="visibleLevel" :level-id="form.grade" @change="handelLevelChange"
			@showTip="onShowTip" />
		<password-input :popupShow.sync="showPassInput" @ok="handelPasswordInputOk" />
		<scanpay-qrcode-popup :qrcodeshow.sync="qrcodeshow" :title="currPayWay.title" :qrcodeurl="qrcodeUrl"
			:copymark="copyMark" @close="handelScanpyQrcodeClose" />
		<alipayuser-popup :show.sync="alipayuserPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
		<open-wind ref="open-wind" title="升级提示" />
	</view>
</template>

<script>
	import {
		mapGetters
	} from 'vuex'
	import PayWay from '../components/PayWay'
	import ChooseLevel from '../components/ChooseLevel/'
	import Schema from 'async-validator'

	import ScanpayQrcodePopup from '@/components/scanpay-qrcode-popup'
	import PasswordInput from '@/components/password-input/index'
	import AlipayUserPopup from '@/components/alipayuser-popup'
	import OpenWind from '@/components/OpenWind/common'
	export default {
		components: {
			'pay-way': PayWay,
			'choose-level': ChooseLevel,
			'password-input': PasswordInput,
			'scanpay-qrcode-popup': ScanpayQrcodePopup,
			'alipayuser-popup': AlipayUserPopup,
			OpenWind
		},
		data() {
			return {
				form: {
					grade: '',
					pay_type: '',
					pay_id: '',
					trade_password: '' //(balance)交易密码
				},
				rules: {
					grade: {
						required: true,
						message: '请选择提升的等级'
					},
					pay_type: {
						required: true,
						message: '请选择支付方式'
					}
				},
				visibleLevel: false,
				currLevel: {},
				currPayWay: {},

				showPassInput: false,
				qrcodeshow: false,
				qrcodeUrl: '',
				copyMark: '',

				payStatusForm: {
					order_sn: ''
				},

				alipayuserPopupShow: false, //显示转账加款弹框
				alipayuserPopupData: {}, //弹框渲染的内容
			}
		},
		computed: {
			...mapGetters(['userinfo']),
			payMoney() {
				return Number(this.currLevel.amount) || 0
			}
		},
		mounted() {

		},
		onLoad(e) {
			const {
				level_id,
			} = e
			if (level_id) {
				this.form.grade = level_id - 0
			}
		},
		methods: {
			handelLevelChange(e) {
				this.form.grade = e.value
				this.currLevel = e
			},
			handelPayWayChange(e) {
				this.form.pay_type = e.name
				if (e.name != 'balance') {
					this.form.pay_id = e.id
				} else this.form.pay_id = ''
				this.currPayWay = e
			},
			doSubmit() {
				// 创建校验器
				const validator = new Schema(this.rules);
				validator.validate(this.form, (errors, fields) => {
					if (errors) {
						this.$util.msg(errors[0].message)
						return
					}
					this.affirmPay()
				})
			},
			async affirmPay() {
				if (this.currPayWay.name == 'balance') {
					if (this.userinfo.trade_password_open && !this.form.trade_password) {
						this.showPassInput = true
					} else {
						this.$u.throttle(() => this.buy(), 1000)
					}

				} else {
					this.$u.throttle(() => this.buy(), 1000)
				}
			},
			async buy() {
				if (this.currPayWay.name == 'balance') {
					await this.doPay()
				} else {
					const {
						url_type,
						url,
						order_sn,
						orderid,
						pay_data,
					} = await this.doPay()
					this.payStatusForm.order_sn = order_sn
					if (this.paystatusTimer) {
						clearInterval(this.paystatusTimer)
						this.paystatusTimer = null
					}
					this.paystatusTimer = setInterval(() => {
						this.paystatus()
					}, 2000)
					let that = this
					switch (url_type) {
						case 1:
							this.qrcodeUrl = url


							//收款人身份
							if (this.currPayWay.name == 'alipayuser' && pay_data && pay_data.true_name) {
								this.copyMark = pay_data.true_name;
							} else {
								this.copyMark = '';
							}

							if (this.currPayWay.name == 'alipay' || this.currPayWay.name == 'alipayuser') {
								this.$util.openAppUrl(this.qrcodeUrl)
							}
							this.qrcodeshow = true

							break;
						case 2:
							//#ifdef MP-WEIXIN
							if (this.currPayWay.name == 'alipay') {
								this.qrcodeUrl = url
								this.qrcodeshow = true
							}
							//#endif
							//#ifdef H5
							window.location.href = url
							//#endif
							break;
						case 3:
							//#ifdef H5
							window.location.href = res.url
							//#endif
							break;
						case 4:
							//#ifdef H5
							jWeixin.config({
								debug: false, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
								appId: pay_data.appId, // 必填，公众号的唯一标识
								timestamp: pay_data.timeStamp, // 必填，生成签名的时间戳
								nonceStr: pay_data.nonceStr, // 必填，生成签名的随机串
								signature: pay_data.paySign, // 必填，签名
								jsApiList: [ //这里是需要用到的接口名称  
									'checkJsApi', //判断当前客户端版本是否支持指定JS接口  
									'onMenuShareAppMessage', //分享接口  
									'getLocation', //获取位置  
									'openLocation', //打开位置  
									'scanQRCode', //扫一扫接口  
									'chooseWXPay', //微信支付  
									'chooseImage', //拍照或从手机相册中选图接口  
									'previewImage', //预览图片接口  
									'uploadImage' //上传图片  
								], // 必填，需要使用的JS接口列表
								openId: this.userinfo.wxgzh_openid
							})
							//付款
							jWeixin.chooseWXPay({
								appId: pay_data.appId,
								timestamp: pay_data
									.timeStamp, // 支付签名时间戳，注意微信jssdk中的所有使用timestamp字段均为小写。但最新版的支付后台生成签名使用的timeStamp字段名需大写其中的S字符
								nonceStr: pay_data.nonceStr, // 支付签名随机串，不长于 32
								package: pay_data
									.package, // 统一支付接口返回的prepay_id参数值，提交格式如：prepay_id=\*\*\*）
								signType: pay_data.signType, // 签名方式，默认为'SHA1'，使用新版支付需传入'MD5'
								paySign: pay_data.paySign, // 支付签名
								success: function(res) {
									// 余额支付直接跳到订单详情
									// that.ordersn = ''
									// that.order_id = ''
									// if (that.paystatusTimer) {
									// 	clearInterval(that.paystatusTimer)
									// }
									// that.$util.msg('支付成功');
									// setTimeout(() => {
									// 	that.$util.on('/pages/order/info?id=' + that.order_id);
									// }, 1000)

								},
								cancel: function(res) {
									that.$util.msg('取消支付');
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
								},
								fail: function(res) {
									that.$util.msg('付款失败');
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}

								}
							});
							//#endif
							break;
						case 5:
							// #ifdef MP
							let mp_pay_name = ''
							if (uni.requestOrderPayment) {
								mp_pay_name = 'requestOrderPayment'
							} else {
								mp_pay_name = 'requestPayment'
							}
							uni.showLoading({
								title: `支付中`
							})
							uni[mp_pay_name]({
								timeStamp: pay_data.timeStamp,
								nonceStr: pay_data.nonceStr,
								package: pay_data.package,
								signType: pay_data.signType,
								paySign: pay_data.paySign,
								success: function(res) {
									uni.hideLoading()
									that.$util.msg(res.msg)
								},
								fail: function(e) {
									uni.hideLoading();
									that.$util.msg('取消支付')
								},
								complete: function(e) {
									uni.hideLoading();
									if (e.errMsg == 'requestPayment:cancel' || e.errMsg ==
										'requestOrderPayment:cancel') return
									that.$util.msg('取消支付');
								},
							});
							// #endif
							break;
						case 6:
							// #ifdef APP-PLUS
							// console.log(res)
							uni.showLoading({
								mask: true,
								title: '支付中...'
							});
							uni.requestPayment({
								provider: 'wxpay',
								orderInfo: pay_data,
								success: (e) => {
									that.$util.msg(`支付成功`)
								},
								fail: (e) => {
									that.$util.msg(`支付失败`)
								},
								complete: () => {
									// 余额支付直接跳到订单详情
									// that.ordersn = ''
									// that.order_id = ''
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
									uni.hideLoading()
								},
							});
							// #endif
							break;
						case 7:
							// #ifdef APP-PLUS
							uni.showLoading({
								mask: true,
								title: '支付中...'
							});
							uni.requestPayment({
								provider: 'alipay',
								orderInfo: pay_data,
								success: (e) => {
									that.$util.msg(`支付成功`)
								},
								fail: (e) => {
									console.log(e)
									that.$util.msg(`支付失败`)
								},
								complete: (e) => {
									console.log(e)
									// 余额支付直接跳到订单详情
									// that.ordersn = ''
									// that.order_id = ''
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
									uni.hideLoading()
								},
							});
							// #endif
							break;
						case 8:
							this.alipayuserPopupData = {
								trade_sn: '',
								order_sn,
								...pay_data
							}
							if (this.alipayuserPopupData.is_trade_sn) {
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
							}
							if (this.alipayuserPopupData.is_need_account) {
								this.$util.msg('请使用支付宝提现账号付款')
								setTimeout(() => {
									this.$util.on('/pages/ucenter_sub/draw')
								}, 2000)
							} else
								this.alipayuserPopupShow = true
							break;
						default:
							break;
					}

				}
			},
			async doPay() {
				try {
					this.loading = true
					const res = await this.$u.api.upgrade(this.form)
					if (this.form.pay_type == 'balance') {
						this.$util.msg('支付成功')
						setTimeout(() => {
							this.$util.on('/pages/ucenter_sub/moneylist');
						}, 1000)
					} else {
						return res
					}
				} catch (e) {
					this.form.trade_password = ''
					if (e.data.msg == "用户余额不足") {
						setTimeout(() => {
							this.$util.on('/pages/ucenter_sub/recharge');
						}, 1000)
					}
				} finally {
					this.loading = false
				}
			},
			async paystatus() {
				try {
					const {
						status,
						url
					} = await this.$u.api.payStatus(this.payStatusForm)
					if (status == 1) {
						this.$util.msg('支付成功')
						clearInterval(this.paystatusTimer)
						this.paystatusTimer = null
						setTimeout(() => {
							this.$util.on(url);
						}, 1000)
					}
				} catch (e) {
					clearInterval(this.paystatusTimer)
					this.paystatusTimer = null
				}
			},
			stopPayStatus() {
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
					this.paystatusTimer = null
				}
			},
			handelPasswordInputOk(e) {
				this.showPassInput = false
				this.form.trade_password = e
				this.buy()
			},
			handelAlipayUserOk({
				url
			}) {
				this.stopPayStatus()

				setTimeout(() => {
					this.$util.on(url)
				}, 1000)
			},
			handelScanpyQrcodeClose() {
				this.stopPayStatus()
			},
			onShowTip(e) {
				this.$refs['open-wind'].show(e)
			}
		},
	}
</script>

<style scoped>
	.page {
		display: flex;
		flex-direction: column;
		gap: 20rpx;
		padding: 20rpx;
		height: auto;
	}

	.info-box {
		border-radius: 10rpx;
		padding: 20rpx;
		background-color: #fff;
	}

	.pay-btn {
		width: 100%;
		display: flex;
		text-align: center;
		height: 40px;
		border-radius: 25px;
		flex-direction: column;
		justify-content: center;
		font-weight: 500;
		font-size: 14px;
		color: #fff;
		background: linear-gradient(90deg, #FE8A56, #FF504B);
	}
</style>